import{_ as t,o as a,c as n,ag as o}from"./chunks/framework.DjqkqlVQ.js";const p=JSON.parse('{"title":"What Slay the Spire 2 Acts Change","description":"","frontmatter":{},"headers":[],"relativePath":"en/knowledge/sts2/acts-map-events.md","filePath":"en/knowledge/sts2/acts-map-events.md","lastUpdated":1778402328000}'),s={name:"en/knowledge/sts2/acts-map-events.md"};function r(d,e,i,l,h,c){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="what-slay-the-spire-2-acts-change" tabindex="-1">What Slay the Spire 2 Acts Change <a class="header-anchor" href="#what-slay-the-spire-2-acts-change" aria-label="Permalink to &quot;What Slay the Spire 2 Acts Change&quot;">​</a></h1><p>This note answers a narrow question: do Overgrowth, Underdocks, Hive, and Glory change unknown rooms, events, enemies, elites, and bosses?</p><p>Short version:</p><ul><li>Acts change map length, unknown count, event pools, normal encounter pools, elite pools, boss pools, ancient pools, background, and music.</li><li>Acts do not directly change the base odds for an unknown room becoming event, normal combat, shop, or treasure.</li><li>So when unknown rooms feel different between acts, the main reasons are the number of unknown nodes and the act-specific event pool used after an unknown room becomes an event.</li></ul><h2 id="two-meanings-of-map" tabindex="-1">Two Meanings of Map <a class="header-anchor" href="#two-meanings-of-map" aria-label="Permalink to &quot;Two Meanings of Map&quot;">​</a></h2><p>Players often use “map” for two different things:</p><table tabindex="0"><thead><tr><th>Phrase</th><th>What it means</th><th>What it changes</th></tr></thead><tbody><tr><td>“This act is Overgrowth / Underdocks / Hive / Glory”</td><td>The area, or act</td><td>Room count, unknown count, event pool, encounter pool, boss pool, and more.</td></tr><tr><td>“What will this unknown become?”</td><td>The room-type roll when entering an unknown node</td><td>Uses a shared base odds system that changes with unknown-room history.</td></tr></tbody></table><h2 id="acts-change-event-pools" tabindex="-1">Acts Change Event Pools <a class="header-anchor" href="#acts-change-event-pools" aria-label="Permalink to &quot;Acts Change Event Pools&quot;">​</a></h2><p>An unknown node first rolls a room type. Only if it becomes an event does the game pull a specific event from the event queue.</p><p>That queue is built from:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>current act events + shared events - locked events</span></span></code></pre></div><p>That is why event themes differ by act:</p><table tabindex="0"><thead><tr><th>Act</th><th style="text-align:right;">Act-specific events</th><th>What feels different</th></tr></thead><tbody><tr><td>Overgrowth</td><td style="text-align:right;">13</td><td>The largest event pool, with forest, plant, nest, carving, spring, and similar themes.</td></tr><tr><td>Underdocks</td><td style="text-align:right;">10</td><td>More underwater, dock, bath, whirlpool, and sunken-treasure themes.</td></tr><tr><td>Hive</td><td style="text-align:right;">10</td><td>More insect, fusion, flower, parasite, and lantern themes.</td></tr><tr><td>Glory</td><td style="text-align:right;">7</td><td>Fewer act-specific events, with training, trial, reflection, and tinkering themes.</td></tr></tbody></table><p>There are also shared events that can appear across acts, such as The Merchant???, Crystal Sphere, Tea Master, Relic Trader, and The Future of Potions. Unlock progress can filter events out before they enter the pool.</p><h2 id="acts-change-monsters-elites-and-bosses" tabindex="-1">Acts Change Monsters, Elites, and Bosses <a class="header-anchor" href="#acts-change-monsters-elites-and-bosses" aria-label="Permalink to &quot;Acts Change Monsters, Elites, and Bosses&quot;">​</a></h2><p>Each act has its own encounter pools:</p><ul><li>Normal combat pulls from the current act&#39;s normal encounter queue.</li><li>Elite combat pulls from the current act&#39;s elite encounter queue.</li><li>Bosses are chosen from the current act&#39;s boss pool. If there are unseen bosses, the game prioritizes discovery order.</li></ul><p>So a normal combat icon does not mean the same thing in every act. The same is true for elites and bosses.</p><h2 id="acts-change-map-length-and-unknown-count" tabindex="-1">Acts Change Map Length and Unknown Count <a class="header-anchor" href="#acts-change-map-length-and-unknown-count" aria-label="Permalink to &quot;Acts Change Map Length and Unknown Count&quot;">​</a></h2><p>Acts also decide how many rooms, unknown nodes, and rest sites appear:</p><table tabindex="0"><thead><tr><th>Act</th><th style="text-align:right;">Base room count</th><th style="text-align:right;">Unknown nodes</th><th style="text-align:right;">Rest sites</th></tr></thead><tbody><tr><td>Overgrowth</td><td style="text-align:right;">15</td><td style="text-align:right;">about 10-14</td><td style="text-align:right;">about 6-7</td></tr><tr><td>Underdocks</td><td style="text-align:right;">15</td><td style="text-align:right;">about 10-14</td><td style="text-align:right;">about 6-7</td></tr><tr><td>Hive</td><td style="text-align:right;">14</td><td style="text-align:right;">about 9-13</td><td style="text-align:right;">about 6-7</td></tr><tr><td>Glory</td><td style="text-align:right;">13</td><td style="text-align:right;">about 9-13</td><td style="text-align:right;">about 5-6</td></tr></tbody></table><p>In multiplayer, each act has one fewer base room.</p><p>This matters because even if the unknown-room roll rules are shared, the act still changes how many unknown rolls you can encounter.</p><h2 id="acts-change-node-distribution" tabindex="-1">Acts Change Node Distribution <a class="header-anchor" href="#acts-change-node-distribution" aria-label="Permalink to &quot;Acts Change Node Distribution&quot;">​</a></h2><p>Standard maps roughly follow these rules:</p><ul><li>The first normal row is fixed to normal combat.</li><li>The row right before the boss is fixed to rest sites.</li><li>A middle row is fixed to treasure; some effects can replace that treasure row with elites.</li><li>Shops default to 3.</li><li>Elites default to 5; the Swarming Elites ascension modifier increases that count.</li><li>Remaining nodes are filled with the act&#39;s rest-site count, unknown count, shops, and elites; leftover nodes become normal combat.</li></ul><p>The map generator also avoids several awkward layouts. For example, elites, rest sites, treasure rooms, and shops are restricted from appearing too directly adjacent to the same type.</p><h2 id="unknown-odds-are-not-act-tables" tabindex="-1">Unknown Odds Are Not Act Tables <a class="header-anchor" href="#unknown-odds-are-not-act-tables" aria-label="Permalink to &quot;Unknown Odds Are Not Act Tables&quot;">​</a></h2><p>The base unknown-room odds are roughly:</p><table tabindex="0"><thead><tr><th>Result</th><th style="text-align:right;">Base odds</th></tr></thead><tbody><tr><td>Normal combat</td><td style="text-align:right;">10%</td></tr><tr><td>Treasure</td><td style="text-align:right;">2%</td></tr><tr><td>Shop</td><td style="text-align:right;">3%</td></tr><tr><td>Event</td><td style="text-align:right;">Remaining odds, initially about 85%</td></tr><tr><td>Elite</td><td style="text-align:right;">Disabled by default</td></tr></tbody></table><p>However, it is not a fixed “85% event” every time. If a non-event result does not roll, its odds increase. If it does roll, that result resets to its base odds. Event odds are the remaining probability, so they fall as monster, treasure, and shop odds build up.</p><p>In practical terms: after several unknown rooms become events, later unknown rooms are more likely to become combat, shops, or treasure. Once combat rolls, combat odds reset.</p><p>These unknown odds are shared rules, not separate Overgrowth, Underdocks, Hive, and Glory tables. Acts affect the outer layers: how many unknown nodes you see and which event queue is used after an unknown becomes an event.</p><h2 id="route-planning-takeaways" tabindex="-1">Route Planning Takeaways <a class="header-anchor" href="#route-planning-takeaways" aria-label="Permalink to &quot;Route Planning Takeaways&quot;">​</a></h2><ul><li>To see more act-specific events, path through more unknown nodes in that act; unknown nodes are not guaranteed events.</li><li>Hive and Glory usually have slightly fewer unknown nodes than Overgrowth and Underdocks.</li><li>If several unknown nodes in a row become events, later unknown nodes are more likely to flip into combat, shop, or treasure.</li><li>Elite, boss, and normal combat difficulty depends on the act&#39;s encounter pools, not just the map icon.</li><li>Unlock progress changes event and ancient pools; new profiles, older profiles, multiplayer, and mods can all change results.</li></ul><h2 id="implementation-details" tabindex="-1">Implementation Details <a class="header-anchor" href="#implementation-details" aria-label="Permalink to &quot;Implementation Details&quot;">​</a></h2><blockquote><p>This section is implementation detail. Skip it if you only care about route planning.</p></blockquote><p>At the code level, acts are defined by <code>ActModel</code> subclasses:</p><table tabindex="0"><thead><tr><th>Act</th><th>Class</th><th>Main configuration</th></tr></thead><tbody><tr><td>Overgrowth</td><td><code>Overgrowth</code></td><td>15 base rooms, 13 act events, 3 weak encounters, 3 boss candidates.</td></tr><tr><td>Underdocks</td><td><code>Underdocks</code></td><td>15 base rooms, 10 act events, 3 weak encounters, 3 boss candidates.</td></tr><tr><td>Hive</td><td><code>Hive</code></td><td>14 base rooms, 10 act events, 2 weak encounters, 3 boss candidates.</td></tr><tr><td>Glory</td><td><code>Glory</code></td><td>13 base rooms, 7 act events, 2 weak encounters, 3 boss candidates.</td></tr></tbody></table><p>The default act list is Overgrowth, Hive, and Glory. Once Underdocks is unlocked, it can replace Act 1; if it has not been discovered yet, non-multiplayer runs prioritize showing it.</p><p>When the game generates room pools, it:</p><ol><li>Combines the current act&#39;s <code>AllEvents</code> with <code>ModelDb.AllSharedEvents</code>.</li><li>Removes events that are still locked by timeline progress.</li><li>Shuffles the result into the act&#39;s event queue.</li><li>Generates normal encounter, elite encounter, boss, and ancient selections.</li><li>When entering an event room, pulls the next valid event and records visited events to avoid repeats when possible.</li></ol><p>Standard maps are generated by <code>StandardActMap</code>. Map RNG is derived from the run seed with an <code>act_N_map</code> stream, so the same seed, act number, and game state tend to reproduce the same map structure and node distribution.</p><p>Unknown-room odds are maintained by <code>UnknownMapPointOdds</code>. The base values are normal combat <code>0.10</code>, treasure <code>0.02</code>, shop <code>0.03</code>, elite <code>-1</code>, and event odds are computed as <code>1 - sum of positive non-event odds</code>. After each roll, the rolled type resets to base odds and available unrolled types increase by their base odds.</p>',44)])])}const m=t(s,[["render",r]]);export{p as __pageData,m as default};
